/* WARNING: Script requires that SQLITE_DBCONFIG_DEFENSIVE be disabled */
PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE workspaces (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  slug TEXT UNIQUE NOT NULL,
  settings TEXT DEFAULT '{}',
  created_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now')),
  updated_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now'))
);
CREATE TABLE users (
  id TEXT PRIMARY KEY,
  workspace_id TEXT NOT NULL REFERENCES workspaces(id),
  name TEXT NOT NULL,
  email TEXT UNIQUE,
  role TEXT NOT NULL DEFAULT 'member',
  api_key_hash TEXT,
  last_seen TEXT,
  created_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now'))
, session_expires_at TEXT);
CREATE TABLE magic_links (
  id TEXT PRIMARY KEY,
  user_id TEXT NOT NULL REFERENCES users(id),
  token_hash TEXT NOT NULL,
  expires_at TEXT NOT NULL,
  used_at TEXT,
  created_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now'))
);
CREATE TABLE agents (
  id TEXT PRIMARY KEY,
  workspace_id TEXT NOT NULL REFERENCES workspaces(id),
  name TEXT NOT NULL,
  type TEXT NOT NULL,
  api_key_hash TEXT NOT NULL,
  key_rotated_at TEXT,
  previous_key_hash TEXT,
  previous_key_expires TEXT,
  permissions TEXT DEFAULT '{}',
  metadata TEXT DEFAULT '{}',
  last_seen TEXT,
  active INTEGER DEFAULT 1,
  created_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now'))
);
CREATE TABLE projects (
  id TEXT PRIMARY KEY,
  workspace_id TEXT NOT NULL REFERENCES workspaces(id),
  name TEXT NOT NULL,
  description TEXT,
  status TEXT NOT NULL DEFAULT 'active',
  owner_agent_id TEXT REFERENCES agents(id),
  color TEXT,
  tags TEXT DEFAULT '[]',
  settings TEXT DEFAULT '{}',
  revision INTEGER NOT NULL DEFAULT 1,
  deleted_at TEXT,
  created_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now')),
  updated_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now')),
  updated_by TEXT
);
CREATE TABLE tasks (
  id TEXT PRIMARY KEY,
  project_id TEXT NOT NULL REFERENCES projects(id),
  workspace_id TEXT NOT NULL REFERENCES workspaces(id),
  title TEXT NOT NULL,
  description TEXT,
  status TEXT NOT NULL DEFAULT 'todo',
  priority TEXT DEFAULT 'medium',
  assignee TEXT,
  due_date TEXT,
  blocked_by TEXT DEFAULT '[]',
  parent_id TEXT REFERENCES tasks(id),
  source TEXT DEFAULT 'manual',
  tags TEXT DEFAULT '[]',
  notes TEXT,
  attachments TEXT DEFAULT '[]',
  revision INTEGER NOT NULL DEFAULT 1,
  deleted_at TEXT,
  created_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now')),
  updated_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now')),
  updated_by TEXT
);
CREATE TABLE deals (
  id TEXT PRIMARY KEY,
  project_id TEXT NOT NULL REFERENCES projects(id),
  workspace_id TEXT NOT NULL REFERENCES workspaces(id),
  name TEXT NOT NULL,
  address TEXT,
  status TEXT NOT NULL DEFAULT 'active',
  asking_price REAL,
  target_price REAL,
  monthly_rent REAL,
  lease_term_months INTEGER,
  metadata TEXT DEFAULT '{}',
  documents TEXT DEFAULT '[]',
  timeline TEXT DEFAULT '[]',
  tags TEXT DEFAULT '[]',
  notes TEXT,
  revision INTEGER NOT NULL DEFAULT 1,
  deleted_at TEXT,
  created_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now')),
  updated_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now')),
  updated_by TEXT
);
CREATE TABLE contacts (
  id TEXT PRIMARY KEY,
  workspace_id TEXT NOT NULL REFERENCES workspaces(id),
  name TEXT NOT NULL,
  role TEXT,
  company TEXT,
  email TEXT,
  phone TEXT,
  telegram_id TEXT,
  language TEXT DEFAULT 'EN',
  timezone TEXT,
  category TEXT,
  communication_rules TEXT,
  tags TEXT DEFAULT '[]',
  notes TEXT,
  revision INTEGER NOT NULL DEFAULT 1,
  deleted_at TEXT,
  created_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now')),
  updated_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now')),
  updated_by TEXT
);
CREATE TABLE finances (
  id TEXT PRIMARY KEY,
  workspace_id TEXT NOT NULL REFERENCES workspaces(id),
  project_id TEXT REFERENCES projects(id),
  type TEXT NOT NULL,
  name TEXT NOT NULL,
  amount REAL NOT NULL,
  currency TEXT DEFAULT 'USD',
  recurring TEXT DEFAULT 'none',
  status TEXT DEFAULT 'active',
  tags TEXT DEFAULT '[]',
  notes TEXT,
  revision INTEGER NOT NULL DEFAULT 1,
  deleted_at TEXT,
  created_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now')),
  updated_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now')),
  updated_by TEXT
);
CREATE TABLE contact_projects (
  contact_id TEXT NOT NULL REFERENCES contacts(id),
  project_id TEXT NOT NULL REFERENCES projects(id),
  role TEXT,
  PRIMARY KEY (contact_id, project_id)
);
CREATE TABLE deal_contacts (
  deal_id TEXT NOT NULL REFERENCES deals(id),
  contact_id TEXT NOT NULL REFERENCES contacts(id),
  role TEXT,
  PRIMARY KEY (deal_id, contact_id)
);
CREATE TABLE activity (
  id TEXT PRIMARY KEY,
  workspace_id TEXT NOT NULL,
  timestamp TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now')),
  actor TEXT NOT NULL,
  action TEXT NOT NULL,
  entity_type TEXT NOT NULL,
  entity_id TEXT,
  project_id TEXT,
  summary TEXT NOT NULL,
  details TEXT DEFAULT '{}',
  revision_before INTEGER,
  revision_after INTEGER
);
CREATE TABLE activity_archive (
  id TEXT PRIMARY KEY,
  workspace_id TEXT NOT NULL,
  timestamp TEXT NOT NULL,
  actor TEXT NOT NULL,
  action TEXT NOT NULL,
  entity_type TEXT NOT NULL,
  entity_id TEXT,
  project_id TEXT,
  summary TEXT NOT NULL,
  details TEXT DEFAULT '{}',
  revision_before INTEGER,
  revision_after INTEGER
);
CREATE TABLE idempotency_keys (
  key_hash TEXT PRIMARY KEY,
  response TEXT NOT NULL,
  created_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now')),
  expires_at TEXT NOT NULL
);
CREATE TABLE webhook_dead_letters (
  id TEXT PRIMARY KEY,
  webhook_url TEXT NOT NULL,
  payload TEXT NOT NULL,
  attempts INTEGER NOT NULL DEFAULT 0,
  last_attempt_at TEXT,
  last_error TEXT,
  created_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now'))
);
CREATE TABLE schema_versions (
  version INTEGER PRIMARY KEY,
  applied_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now')),
  description TEXT
);
PRAGMA writable_schema=ON;
CREATE TABLE IF NOT EXISTS 'tasks_fts_data'(id INTEGER PRIMARY KEY, block BLOB);
CREATE TABLE IF NOT EXISTS 'tasks_fts_idx'(segid, term, pgno, PRIMARY KEY(segid, term)) WITHOUT ROWID;
CREATE TABLE IF NOT EXISTS 'tasks_fts_docsize'(id INTEGER PRIMARY KEY, sz BLOB);
CREATE TABLE IF NOT EXISTS 'tasks_fts_config'(k PRIMARY KEY, v) WITHOUT ROWID;
CREATE TABLE IF NOT EXISTS 'contacts_fts_data'(id INTEGER PRIMARY KEY, block BLOB);
CREATE TABLE IF NOT EXISTS 'contacts_fts_idx'(segid, term, pgno, PRIMARY KEY(segid, term)) WITHOUT ROWID;
CREATE TABLE IF NOT EXISTS 'contacts_fts_docsize'(id INTEGER PRIMARY KEY, sz BLOB);
CREATE TABLE IF NOT EXISTS 'contacts_fts_config'(k PRIMARY KEY, v) WITHOUT ROWID;
CREATE TABLE IF NOT EXISTS 'deals_fts_data'(id INTEGER PRIMARY KEY, block BLOB);
CREATE TABLE IF NOT EXISTS 'deals_fts_idx'(segid, term, pgno, PRIMARY KEY(segid, term)) WITHOUT ROWID;
CREATE TABLE IF NOT EXISTS 'deals_fts_docsize'(id INTEGER PRIMARY KEY, sz BLOB);
CREATE TABLE IF NOT EXISTS 'deals_fts_config'(k PRIMARY KEY, v) WITHOUT ROWID;
CREATE TABLE IF NOT EXISTS 'activity_fts_data'(id INTEGER PRIMARY KEY, block BLOB);
CREATE TABLE IF NOT EXISTS 'activity_fts_idx'(segid, term, pgno, PRIMARY KEY(segid, term)) WITHOUT ROWID;
CREATE TABLE IF NOT EXISTS 'activity_fts_docsize'(id INTEGER PRIMARY KEY, sz BLOB);
CREATE TABLE IF NOT EXISTS 'activity_fts_config'(k PRIMARY KEY, v) WITHOUT ROWID;
CREATE TABLE oauth_clients (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  agent_id TEXT REFERENCES agents(id),
  client_secret_hash TEXT NOT NULL,
  redirect_uris TEXT NOT NULL DEFAULT '[]',
  created_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now'))
);
CREATE TABLE oauth_codes (
  code_hash TEXT PRIMARY KEY,
  client_id TEXT NOT NULL REFERENCES oauth_clients(id),
  redirect_uri TEXT NOT NULL,
  workspace_id TEXT NOT NULL,
  agent_id TEXT NOT NULL,
  code_challenge TEXT NOT NULL,
  code_challenge_method TEXT NOT NULL DEFAULT 'S256',
  expires_at TEXT NOT NULL,
  used INTEGER NOT NULL DEFAULT 0,
  created_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now'))
);
CREATE TABLE oauth_tokens (
  token_hash TEXT PRIMARY KEY,
  client_id TEXT NOT NULL REFERENCES oauth_clients(id),
  agent_id TEXT NOT NULL,
  workspace_id TEXT NOT NULL,
  token_type TEXT NOT NULL DEFAULT 'refresh_token',
  expires_at TEXT NOT NULL,
  revoked INTEGER NOT NULL DEFAULT 0,
  created_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now'))
);
CREATE TABLE notes (
  id TEXT PRIMARY KEY,
  workspace_id TEXT NOT NULL REFERENCES workspaces(id),
  agent_id TEXT,
  agent_name TEXT,
  session_id TEXT,
  text TEXT NOT NULL,
  project_id TEXT REFERENCES projects(id),
  source TEXT DEFAULT 'manual',
  embedding BLOB,
  matched_entities TEXT DEFAULT '[]',
  auto_updates TEXT DEFAULT '[]',
  created_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now'))
);
/****** CORRUPTION ERROR *******/
CREATE TABLE IF NOT EXISTS 'notes_fts_data'(id INTEGER PRIMARY KEY, block BLOB);
CREATE TABLE IF NOT EXISTS 'notes_fts_idx'(segid, term, pgno, PRIMARY KEY(segid, term)) WITHOUT ROWID;
CREATE TABLE IF NOT EXISTS 'notes_fts_docsize'(id INTEGER PRIMARY KEY, sz BLOB);
CREATE TABLE IF NOT EXISTS 'notes_fts_config'(k PRIMARY KEY, v) WITHOUT ROWID;
CREATE TRIGGER tasks_fts_ai AFTER INSERT ON tasks BEGIN
  VALUES (new.rowid, new.title, new.description, new.notes);
END;
CREATE TRIGGER tasks_fts_ad AFTER DELETE ON tasks BEGIN
  VALUES ('delete', old.rowid, old.title, old.description, old.notes);
END;
CREATE TRIGGER tasks_fts_au AFTER UPDATE ON tasks BEGIN
  VALUES ('delete', old.rowid, old.title, old.description, old.notes);
  VALUES (new.rowid, new.title, new.description, new.notes);
END;
CREATE TRIGGER contacts_fts_ai AFTER INSERT ON contacts BEGIN
  VALUES (new.rowid, new.name, new.role, new.company, new.notes);
END;
CREATE TRIGGER contacts_fts_ad AFTER DELETE ON contacts BEGIN
  VALUES ('delete', old.rowid, old.name, old.role, old.company, old.notes);
END;
CREATE TRIGGER contacts_fts_au AFTER UPDATE ON contacts BEGIN
  VALUES ('delete', old.rowid, old.name, old.role, old.company, old.notes);
  VALUES (new.rowid, new.name, new.role, new.company, new.notes);
END;
CREATE TRIGGER deals_fts_ai AFTER INSERT ON deals BEGIN
  VALUES (new.rowid, new.name, new.address, new.notes);
END;
CREATE TRIGGER deals_fts_ad AFTER DELETE ON deals BEGIN
  VALUES ('delete', old.rowid, old.name, old.address, old.notes);
END;
CREATE TRIGGER deals_fts_au AFTER UPDATE ON deals BEGIN
  VALUES ('delete', old.rowid, old.name, old.address, old.notes);
  VALUES (new.rowid, new.name, new.address, new.notes);
END;
CREATE TRIGGER activity_fts_ai AFTER INSERT ON activity BEGIN
  VALUES (new.rowid, new.summary);
END;
CREATE TRIGGER activity_fts_ad AFTER DELETE ON activity BEGIN
  VALUES ('delete', old.rowid, old.summary);
END;
CREATE TRIGGER activity_fts_au AFTER UPDATE ON activity BEGIN
  VALUES ('delete', old.rowid, old.summary);
  VALUES (new.rowid, new.summary);
END;
CREATE TRIGGER notes_fts_ai AFTER INSERT ON notes BEGIN
END;
CREATE TRIGGER notes_fts_ad AFTER DELETE ON notes BEGIN
END;
CREATE TRIGGER notes_fts_au AFTER UPDATE ON notes BEGIN
END;
CREATE INDEX idx_magic_links_user ON magic_links(user_id) WHERE used_at IS NULL;
CREATE INDEX idx_magic_links_token ON magic_links(token_hash) WHERE used_at IS NULL;
CREATE INDEX idx_tasks_project ON tasks(project_id) WHERE deleted_at IS NULL AND status != 'cancelled';
CREATE INDEX idx_tasks_workspace ON tasks(workspace_id, status) WHERE deleted_at IS NULL;
CREATE INDEX idx_tasks_assignee ON tasks(assignee) WHERE status IN ('todo','in_progress','waiting') AND deleted_at IS NULL;
CREATE INDEX idx_tasks_due ON tasks(due_date) WHERE status IN ('todo','in_progress','waiting') AND due_date IS NOT NULL AND deleted_at IS NULL;
CREATE INDEX idx_tasks_updated ON tasks(updated_at) WHERE deleted_at IS NULL;
CREATE INDEX idx_deals_project ON deals(project_id) WHERE deleted_at IS NULL;
CREATE INDEX idx_deals_workspace ON deals(workspace_id) WHERE deleted_at IS NULL;
CREATE INDEX idx_deals_updated ON deals(updated_at) WHERE deleted_at IS NULL;
CREATE INDEX idx_contacts_workspace ON contacts(workspace_id) WHERE deleted_at IS NULL;
CREATE INDEX idx_contacts_updated ON contacts(updated_at) WHERE deleted_at IS NULL;
CREATE INDEX idx_finances_workspace ON finances(workspace_id) WHERE deleted_at IS NULL;
CREATE INDEX idx_finances_updated ON finances(updated_at) WHERE deleted_at IS NULL;
CREATE INDEX idx_projects_workspace ON projects(workspace_id) WHERE deleted_at IS NULL;
CREATE INDEX idx_projects_updated ON projects(updated_at) WHERE deleted_at IS NULL;
CREATE INDEX idx_activity_workspace ON activity(workspace_id, timestamp DESC);
CREATE INDEX idx_activity_entity ON activity(entity_type, entity_id);
CREATE INDEX idx_activity_timestamp ON activity(timestamp);
CREATE INDEX idx_activity_archive_workspace ON activity_archive(workspace_id, timestamp DESC);
CREATE INDEX idx_agents_workspace ON agents(workspace_id) WHERE active = 1;
CREATE INDEX idx_contact_projects_project ON contact_projects(project_id);
CREATE INDEX idx_deal_contacts_contact ON deal_contacts(contact_id);
CREATE INDEX idx_idempotency_expires ON idempotency_keys(expires_at);
CREATE INDEX idx_dead_letters_created ON webhook_dead_letters(created_at);
CREATE INDEX idx_oauth_codes_client ON oauth_codes(client_id);
CREATE INDEX idx_oauth_codes_expires ON oauth_codes(expires_at);
CREATE INDEX idx_oauth_tokens_client ON oauth_tokens(client_id);
CREATE INDEX idx_oauth_tokens_agent ON oauth_tokens(agent_id);
CREATE INDEX idx_oauth_tokens_expires ON oauth_tokens(expires_at) WHERE revoked = 0;
CREATE INDEX idx_oauth_clients_agent ON oauth_clients(agent_id);
CREATE INDEX idx_notes_workspace ON notes(workspace_id, created_at DESC);
CREATE INDEX idx_notes_agent ON notes(agent_name, created_at DESC);
CREATE INDEX idx_notes_project ON notes(project_id) WHERE project_id IS NOT NULL;
PRAGMA writable_schema=OFF;
ROLLBACK; -- due to errors
