INSERT INTO activity VALUES('01KMPWJ13WG1Z95MZHW7ZF1APT','01KMKRVYF2FN68D9N3C8BEGAHS','2026-03-27T05:34:01Z','claude-chat','report','activity',NULL,NULL,'GitHub vulnerability (esbuild 0.19.12 moderate) — closed. Aidan удалил из lockfile (-1133 строки), остался только esbuild 0.27.4 (безопасный, через tsx/vite). Dependabot автоматически пометил fixed. Побочная находка: на новом Mac Mini сломан xcode-select (CLT receipts missing) — не срочно, Qoopia работает с текущими бинарями. Qoopia GitHub public launch Phase 1 полностью завершён: 15/20 issues, README, vulnerability fix, repo public.','{"agent_name":"claude-chat","matched_entities":[{"type":"task","id":"01KMKRVYF8B1KJV7JV1HZ4MD4E","name":"Qoopia: GitHub public launch (Phase 1)","confidence":"high"},{"type":"task","id":"01KMKRVYF9H32B1T540QZDXWJ7","name":"Stepper: GitHub public launch (Фаза 1)","confidence":"medium"},{"type":"task","id":"01KMKRVYF8CCYGC50PKX7SR8Q2","name":"GitHub Sync настроен","confidence":"medium"},{"type":"task","id":"01KMKRVYF61MEDTQDP44KXJJN9","name":"Миграция КЗ-направления с Aidan на Aizek","confidence":"medium"},{"type":"task","id":"01KMKRVYF9BCQ016SW9DAQZ41X","name":"Старый Mac Mini убрать из Tailscale","confidence":"medium"},{"type":"task","id":"01KMKRVYF8HEAK8M667V27E0AA","name":"Mac Mini Migration - перенос OpenClaw на новый Mac","confidence":"medium"},{"type":"task","id":"01KMKRVYF9NGTFR6366R01V945","name":"Qoopia ребрендинг + домены","confidence":"medium"},{"type":"task","id":"01KMP64BDMA33RQ1ZK13WP5SWC","name":"Qoopia V2 LIVE + MCP connector + 25 tools","confidence":"medium"},{"type":"task","id":"01KMPERGDX16283EMH5VEHBCTK","name":"Qoopia Memory Layer: note / recall / brief deployed","confidence":"medium"},{"type":"task","id":"01KMKRVYF906HCMF6HGS2N6SN3","name":"Qoopia Phase 2: conflict resolution, schema, rollback","confidence":"medium"},{"type":"task","id":"01KMKRVYF90MPBBZHDC1CZBKCY","name":"Fix heartbeat calendar check (HTTP 400)","confidence":"medium"},{"type":"task","id":"01KMP64R2YQNPFPC6AHYYPT5W9","name":"Gmail hook fix (channel telegram→last)","confidence":"medium"},{"type":"task","id":"01KMPB57M9EKGSZPHBS6GZZQ8N","name":"Activity-First MCP: report_activity + smart responses + /observe","confidence":"medium"}],"entities_hint":["01KMKRVYF8B1KJV7JV1HZ4MD4E"]}',NULL,NULL);
INSERT INTO activity VALUES('01KMPX1FJNAY63NJR25GG064HW','01KMKRVYF2FN68D9N3C8BEGAHS','2026-03-27T05:42:28Z','claude-chat','report','activity',NULL,NULL,'CLT переустановлен, better-sqlite3 пересобран, node-gyp работает. Все инфраструктурные задачи ночи закрыты. Итог дня 26 марта: Qoopia public launch (github.com/qoopia/qoopia), 15/20 issues fixed, README 3 раунда ревью, esbuild vulnerability closed, CLT/node-gyp fixed, Anthropic outage диагностирован и обойдён (GPT-5.4 fallback → Opus restored). Все 3 агента на Opus.','{"agent_name":"claude-chat","matched_entities":[{"type":"task","id":"01KMKRVYF9NGTFR6366R01V945","name":"Qoopia ребрендинг + домены","confidence":"medium"},{"type":"task","id":"01KMP64BDMA33RQ1ZK13WP5SWC","name":"Qoopia V2 LIVE + MCP connector + 25 tools","confidence":"medium"},{"type":"task","id":"01KMPERGDX16283EMH5VEHBCTK","name":"Qoopia Memory Layer: note / recall / brief deployed","confidence":"medium"},{"type":"task","id":"01KMKRVYF9H32B1T540QZDXWJ7","name":"Stepper: GitHub public launch (Фаза 1)","confidence":"medium"},{"type":"task","id":"01KMKRVYF8B1KJV7JV1HZ4MD4E","name":"Qoopia: GitHub public launch (Phase 1)","confidence":"medium"},{"type":"task","id":"01KMKRVYF8CCYGC50PKX7SR8Q2","name":"GitHub Sync настроен","confidence":"medium"},{"type":"task","id":"01KMKRVYF9XYH3BD8MF5FK1B97","name":"GPT-5.4 как FB1 во всех 3 агентах","confidence":"medium"},{"type":"task","id":"01KMPB4ZCCZ7HGNBMX17JPBJAK","name":"Claude Code: Opus по умолчанию + таймаут 20 мин","confidence":"medium"},{"type":"task","id":"01KMKRVYF90BC0ZHX6YX8SFG52","name":"Aizek: переключить primary с Opus на Sonnet","confidence":"medium"}]}',NULL,NULL);
