INSERT INTO notes VALUES('01KMRRBSYN695ZFEP8ZCCNBGG2','01KMKRVYF2FN68D9N3C8BEGAHS','01KMKRVYF3YW28Q3P5EPSYC9M1','claude',NULL,'Auto-status sync implemented and deployed. Fix for the gap between activity log and task statuses. Changes: (1) New detectAndApplyStatusChanges() in intelligence.ts with confidence gate — high → auto-update, medium → suggested only, low → ignore. (2) All 4 activity-writing paths now go through unified pipeline: note, report_activity, create_activity, observe webhook. (3) brief now cross-references recent activity against task.updated_at and adds stale_warning field when inconsistency detected. (4) Recursion guard in activity-log.ts. (5) 6 tests passing, build clean. Issue discovered during Claude Cowork session — brief returned stale in_progress status for Qoopia launch task while activity log already had "Phase 1 COMPLETE" from Aidan. Root cause: create_activity path bypassed matching pipeline. Now fixed.',NULL,'mcp',NULL,'[{"type":"task","id":"01KMKRVYF8CCYGC50PKX7SR8Q2","name":"GitHub Sync настроен","confidence":"medium"},{"type":"task","id":"01KMKRVYF9S9BBKYPDZ0XD3ZKC","name":"Zoe File Bridge: shared/zoe → auto-sync → Zoe inbox","confidence":"medium"},{"type":"task","id":"01KMKRVYF9KVKKMG7PRSHG9859","name":"MCP Filesystem Server deployed","confidence":"medium"},{"type":"task","id":"01KMKRVYF9RSBSQT9T3B5KW190","name":"Lossless-Claw v0.4.0 deployed to Alan & Aizek","confidence":"medium"},{"type":"task","id":"01KMPERGDX16283EMH5VEHBCTK","name":"Qoopia Memory Layer: note / recall / brief deployed","confidence":"medium"},{"type":"task","id":"01KMKRVYF90MPBBZHDC1CZBKCY","name":"Fix heartbeat calendar check (HTTP 400)","confidence":"medium"},{"type":"task","id":"01KMP64R2YQNPFPC6AHYYPT5W9","name":"Gmail hook fix (channel telegram→last)","confidence":"medium"},{"type":"task","id":"01KMKRVYF87N6RJR3GBS4X7MR2","name":"Review stepper-reconcile dry-run logs and enable live mode","confidence":"medium"},{"type":"task","id":"01KMKRVYF8MXDG4F6T8RNQMZVN"