INSERT INTO notes VALUES('01KMRWH8YR12RN0V2D8BC0ZNMN','01KMKRVYF2FN68D9N3C8BEGAHS','01KMKRVYF3YW28Q3P5EPSYC9M1','claude',NULL,'FINAL logo decided. Created in Canva, design ID: DAHFMMNTUh4. Design: blue circle (#00B0FF / bright cyan-blue) + "qoopia" wordmark in dark navy sans-serif font. Circle is solid, slightly smaller than letter "o". Horizontal layout, minimal, clean. Canva edit link: https://www.canva.com/design/DAHFMMNTUh4/edit. This replaces all previous SVG logo iterations (pyramid versions are deprecated). Askhat made final adjustments directly in Canva.',NULL,'mcp',NULL,'[{"type":"task","id":"01KMKRVYF8JN5VJBPNXK8JMQJ0","name":"SSoT FINAL PLAN — имплементация 5 эшелонов защиты","confidence":"medium"},{"type":"task","id":"01KMKRVYF9KDDS81EFEENGFYN8","name":"Agents HQ Telegram forum created","confidence":"medium"},{"type":"task","id":"01KMKRVYF8B1KJV7JV1HZ4MD4E","name":"Qoopia: GitHub public launch (Phase 1)","confidence":"medium"},{"type":"task","id":"01KMKRVYF9NGTFR6366R01V945","name":"Qoopia ребрендинг + домены","confidence":"medium"},{"type":"task","id":"01KMP64BDMA33RQ1ZK13WP5SWC","name":"Qoopia V2 LIVE + MCP connector + 25 tools","confidence":"medium"},{"type":"task","id":"01KMKRVYF8PV3N822ZSWZ1MNK5","name":"Zombie MCP processes — cron cleanup","confidence":"medium"}]','[]','2026-03-28T00:12:05Z');
INSERT INTO notes VALUES('01KMS8PR1K2ENKARMP1JWQ60QM','01KMKRVYF2FN68D9N3C8BEGAHS','01KMKRVYF3YW28Q3P5EPSYC9M1','claude',NULL,unistr('INCIDENT POST-MORTEM: Qoopia Server Down — March 27, 2026\u000a\u000a## WHAT HAPPENED\u000a\u000aOn the evening of March 27, 2026, the Qoopia V2 server went down after Aidan attempted a gateway restart. The server remained down for approximately 2 hours until Claude (via Cowork) diagnosed and fixed the issues.\u000a\u000a## ROOT CAUSES (5 separate failures)\u000a\u000a### 1. launchctl kickstart killed the Node.js process\u000aAidan used launchctl kickstart to restart the Cloudflare tunnel. This killed the running Qoopia server process as a side effect. There was no process manager to automatically restart it.\u000a\u000a### 2. Node version mismatch — better-sqlite3 native module\u000aThe better-sqlite3 native addon was compiled for Node 24 (MODULE_VERSION 137). But start.sh launched Node 22 (MODULE_VERSION 127). Every restart attempt crashed immediately with "Module was compiled against a different Node.js version."\u000a\u000a### 3. Port mismatch — server default 3000 vs tunnel expects 3737\u000aCloudflare Tunnel config (~/.cloudflared/config.yml) routes mcp.qoopia.ai to localhost:3737. But the server defaults to port 3000 without a PORT env variable. Even after fixing the Node version, the server would start on the wrong port and the tunnel would still show 502.\u000a\u000a### 4. Stale dist/public/ — build does not copy static assets\u000aRunning tsc (TypeScript compiler) only transpiles .ts files to dist/. It does NOT copy static files (HTML, SVG) from src/public/ to dist/public/. So after a rebuild, dist/public/ contained the OLD index.html (17942 bytes — early landing page) while the current dashboard.html (29983 bytes — with Dan, Claude, activity names, filters) existed only in src/public/.\u000a\u000a### 5. Context loss cascade\u000aAfter the first failure, Aidan lost conversation context and began making increasingly destructive attempts to fix things. Without a clear runbook or escalation path, each attempt made things worse.\u000a\u000a## HOW IT WAS FIXED\u000a\u000a1. Found correct server path: ~/.openclaw/qoopia (not ~/qoopia)\u000a2. Killed stale processes: lsof -ti:3000 and :3737 | xargs kill -9\u000a3. Rebuilt native module: npm rebuild better-sqlite3 (recompiled for Node 24)\u000a4. Started with correct port: PORT=3737 npm start\u000a5. Copied dashboard: cp src/public/dashboard.html dist/public/dashboard.html\u000a6. Created LaunchAgent: ~/Library/LaunchAgents/ai.qoopia.server.plist with correct Node path, PORT=3737, RunAtLoad=true, KeepAlive=true\u000a\u000a## PROPOSED SAFEGUARDS (from Claude — for Aidan to review)\u000a\u000a### Safeguard 1: Fix the build pipeline\u000aCurrent: "build": "tsc" — only compiles TypeScript, ignores static assets.\u000aProposed change in package.json:\u000a  "build": "tsc && cp -r src/public/* dist/public/"\u000a  "postbuild": "node -e \\"const s=require(''fs'');[''dashboard.html'',''index.html''].forEach(f=>{if(!s.existsSync(''dist/public/''+f)){console.error(''MISSING: dist/public/''+f);process.exit(1)}})\\""\u000aThe postbuild script verifies critical files exist after build. Build fails if they are missing.\u000a\u000a### Safeguard 2: Pin Node version explicitly\u000aCreate ~/.openclaw/qoopia/.nvmrc with content: v24.14.0\u000aAdd to package.json: "engines": { "node": ">=24.0.0" }\u000aThe LaunchAgent already hardcodes the full Node 24 path. But .nvmrc ensures any shell session in the qoopia directory also uses the right version (nvm use auto).\u000a\u000a### Safeguard 3: deploy.sh — single safe deployment command\u000aCreate ~/.openclaw/qoopia/deploy.sh:\u000a  #!/bin/bash\u000a  set -e\u000a  cd ~/.openclaw/qoopia\u000a  echo "[1/5] Building..."\u000a  npm run build\u000a  echo "[2/5] Verifying dist/public/ assets..."\u000a  for f in dashboard.html; do\u000a    if [ ! -f "dist/public/$f" ]; then\u000a      echo "FATAL: dist/public/$f missing after build!"\u000a      exit 1\u000a    fi\u000a  done\u000a  echo "[3/5] Restarting server..."\u000a  launchctl kickstart -k gui/$(id -u)/ai.qoopia.server\u000a  sleep 3\u000a  echo "[4/5] Health check..."\u000a  STATUS=$(curl -s -o /dev/null -w "%{http_code}" http://localhost:3737/api/v1/agents)\u000a  if [ "$STATUS" = "401" ] || [ "$STATUS" = "200" ]; then\u000a    echo "[5/5] Deploy OK — server responding HTTP $STATUS"\u000a  else\u000a    echo "DEPLOY FAILED — HTTP $STATUS — check /tmp/qoopia-stderr.log"\u000a    exit 1\u000a  fi\u000aNever restart the server directly. Always use deploy.sh.\u000a\u000a### Safeguard 4: Health check cron (watchdog)\u000aAdd to crontab:\u000a  */5 * * * * curl -sf http://localhost:3737/api/v1/agents > /dev/null 2>&1 || (launchctl kickstart -k gui/$(id -u)/ai.qoopia.server && echo "$(date) Qoopia auto-restarted" >> /tmp/qoopia-watchdog.log)\u000aEvery 5 minutes: if server is not responding, auto-restart and log it.\u000a\u000a### Safeguard 5: Agent escalation rule\u000aNew rule for ALL agents: If a server/infrastructure fix attempt fails ONCE, STOP. Write a note to Qoopia memory describing the error. Do NOT attempt further fixes. Notify the owner (Askhat) immediately. The cost of a 30-minute delay is nothing compared to the cost of cascading failures from panicked retry attempts.\u000a\u000a### Safeguard 6: Pre-flight checklist before ANY infrastructure change\u000aBefore touching launchctl, tunnel, gateway, or server restart:\u000a  1. Verify current server status: curl http://localhost:3737/api/v1/agents\u000a  2. Note the current Node version: node -v\u000a  3. Note the current server PID: lsof -ti:3737\u000a  4. Make sure you know how to restart: cat ~/Library/LaunchAgents/ai.qoopia.server.plist\u000a  5. Only then proceed with the change\u000a  6. Immediately verify after: curl http://localhost:3737/api/v1/agents\u000a\u000aAIDAN: Review all 6 safeguards. Evaluate feasibility. Propose improvements or alternatives. Do NOT implement anything — just analyze and give feedback. Write your response as a note to Qoopia.'),NULL,'mcp',NULL,'[{"type":"task","id":"01KMKRVYF8B1KJV7JV1HZ4MD4E","name":"Qoopia: GitHub public launch (Phase 1)","confidence":"medium"},{"type":"task","id":"01KMKRVYF9NGTFR6366R01V945","name":"Qoopia ребрендинг + домены","confidence":"medium"},{"type":"task","id":"01KMP64BDMA33RQ1ZK13WP5SWC","name":"Qoopia V2 LIVE + MCP connector + 25 tools","confidence":"medium"},{"type":"task","id":"01KMKRVYF9KVKKMG7PRSHG9859","name":"MCP Filesystem Server deployed","confidence":"medium"},{"type":"task","id":"01KMKRVYF7TTYB8G9M2NPX6CNW","name":"Получить от Ali: P&L monthly 2025, equipment list, NNN breakdown","confidence":"medium","previous_status":"paused","new_status":"done"},{"type":"task","id":"01KMKRVYF8J8R1A6QZ3NJDDAX4","name":"Обновить Codex OAuth (expires 2026-03-27 22:23 CST)","confidence":"medium"},{"type":"task","id":"01KMKRVYF8MXDG4F6T8RNQMZVN","name":"Gmail Pub/Sub watch renewal (expires 2026-03-26)","confidence":"medium"},{"type":"task","id":"01KMKRVYF9XRT2ZMP5HSGQ96NC","name":"OpenClaw v2026.3.13 -> v2026.3.22","confidence":"medium"},{"type":"task","id":"01KMP63V59772Q13X2C5J5TC1Y","name":"WhatsApp интеграция OpenClaw","confidence":"medium"},{"type":"task","id":"01KMP642THGR5H0DC5M39V6AG0","name":"Правило 25 AGENTS.md: WhatsApp config protection","confidence":"medium"},{"type":"task","id":"01KMKRVYF61MEDTQDP44KXJJN9","name":"Миграция КЗ-направления с Aidan на Aizek","confidence":"medium"},{"type":"task","id":"01KMKRVYF932MHQ6WNVMN8844X","name":"Zoe: Сауле — openclaw configure --section model (Claude Max OAuth)","confidence":"medium"},{"type":"task","id":"01KMP64K3A4BE134Y8YQWES6BB","name":"Claude Max переподписка Apple→Web ($200/мес)","confidence":"medium"},{"type":"task","id":"01KMPB4ZCCZ7HGNBMX17JPBJAK","name":"Claude Code: Opus по умолчанию + таймаут 20 мин","confidence":"medium"},{"type":"task","id":"01KMKRVYF8PV3N822ZSWZ1MNK5","name":"Zombie MCP processes — cron cleanup","confidence":"medium"},{"type":"task","id":"01KMPB57M9EKGSZPHBS6GZZQ8N","name":"Activity-First MCP: report_activity + smart responses + /observe","confidence":"medium"},{"type":"task","id":"01KMKRVYF8AZN63161RQW0NVCC","name":"Batch 5 фото 1: Happy Cake 3000 (Napoleon) - публикация 22 марта","confidence":"medium"},{"type":"task","id":"01KMKRVYF6BX5R24QG4HHG9Y8C","name":"Добавить поле district в stores API (разбивка по районам Астаны)","confidence":"medium"},{"type":"task","id":"01KMKRVYF9H32B1T540QZDXWJ7","name":"Stepper: GitHub public launch (Фаза 1)","confidence":"medium","previous_status":"cancelled","new_status":"done"},{"type":"task","id":"01KMKRVYF9A3KX0J3BSXY6FTCH","name":"SSoT архитектура: stepper/data = факты, CONTEXT.md = стратегия","confidence":"medium"}]','[]','2026-03-28T03:44:48Z');
