INSERT INTO notes VALUES('01KMPR5GR2YHVFM4GTARMYVQSW','01KMKRVYF2FN68D9N3C8BEGAHS','2026-03-27T04:17:17Z','claude','report','activity',NULL,NULL,'Anthropic восстановился. Все 3 агента возвращены на Opus: Alan проверен первым (тест OK), затем Aizek, затем Aidan. Инцидент длился ~40 минут (21:53-22:35 CDT). Временно использовали GPT-5.4 как primary. Бэкапы конфигов: openclaw.json.bak-opus и openclaw.json.bak-gpt54 в каждом workspace.','{"agent_name":"claude-chat","matched_entities":[{"type":"task","id":"01KMPB4ZCCZ7HGNBMX17JPBJAK","name":"Claude Code: Opus по умолчанию + таймаут 20 мин","confidence":"medium"},{"type":"task","id":"01KMKRVYF90BC0ZHX6YX8SFG52","name":"Aizek: переключить primary с Opus на Sonnet","confidence":"medium"},{"type":"task","id":"01KMKRVYF9RSBSQT9T3B5KW190","name":"Lossless-Claw v0.4.0 deployed to Alan & Aizek","confidence":"medium"},{"type":"task","id":"01KMKRVYF8JGV232BC7PKWPSFW","name":"Alan/Aizek memory/ — ждём первых записей","confidence":"medium"},{"type":"task","id":"01KMKRVYF61MEDTQDP44KXJJN9","name":"Миграция КЗ-направления с Aidan на Aizek","confidence":"medium"},{"type":"task","id":"01KMKRVYF9XYH3BD8MF5FK1B97","name":"GPT-5.4 как FB1 во всех 3 агентах","confidence":"medium"},{"type":"task","id":"01KMKRVYF8HEAK8M667V27E0AA","name":"Mac Mini Migration - перенос OpenClaw на новый Mac","confidence":"medium"},{"type":"task","id":"01KMKRVYF8A2W9T2TM0PH2FM0B","name":"Zoe - деплой OpenClaw для Сауле","confidence":"medium"},{"type":"task","id":"01KMKRVYF9XRT2ZMP5HSGQ96NC","name":"OpenClaw v2026.3.13 -> v2026.3.22","confidence":"medium"},{"type":"task","id":"01KMKRVYF8W8HJFWY25HYR4J80","name":"Google Workspace trial end 2026-04-01","confidence":"medium"}]}',NULL,NULL);
